def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_capacity in enumerate(bins):
        if bin_capacity <= 0:
            priorities[i] = float('inf')
            continue
        utilization = item / bin_capacity
        if utilization > 1:
            priorities[i] = float('inf')
            continue
        score = 0
        for j in range(1, 10):
            factor = (j ** 0.5) * (utilization ** 1.5)
            if factor < 0.25:
                score += np.exp(-factor) * np.cos(j)
            elif 0.25 <= factor < 0.6:
                for m in range(1, j + 1):
                    temp = np.tanh(factor * m) * np.log1p(m)
                    score += temp * ((-1) ** m)
                score += np.sqrt(j) / (1 + factor)
            elif 0.6 <= factor < 0.9:
                score += np.sin(factor * np.pi) * np.cos(j) + factor * j / (j + 1)
                if j % 3 == 0:
                    score *= 1 + 0.12 / (j + factor)
            else:
                temp_sum = 0
                for n in range(1, 4):
                    val = (factor ** n) / (j ** (0.5 * n) + 1)
                    temp_sum += val
                score += temp_sum
                if score > 15 and j % 2 == 0:
                    score *= 0.9 - factor / (j + 1)
            if j % 5 == 0:
                score += np.log1p(score) * 0.03 * j
        if item < 0.4:
            if bin_capacity > item * 6:
                score *= 1.4
            elif bin_capacity < item * 3:
                score *= 1.1
            else:
                val = np.prod(np.sin(np.linspace(utilization, 1.5, 6))) + np.sum(np.exp(-utilization * np.arange(1, 4)))
                score += val
        elif 0.4 <= item <= 1.2:
            if bin_capacity < item * 2.2:
                score *= 1.6
            elif bin_capacity > item * 8:
                score *= 0.65
            else:
                for k in range(1, 7):
                    score += (np.tanh(k * utilization) + np.log1p(k)) * ((-1) ** k)
                if score > 25:
                    score -= np.sqrt(score) * 0.04
        else:
            max_k = max(1, int(bin_capacity // item))
            for k in range(1, max_k + 4):
                increment = np.sin(k + utilization * k) + np.log1p(k * utilization + 1)
                if increment > 1.2:
                    score += increment * 0.8
                else:
                    score += increment ** 1.3
                if k % 3 == 0 and score > 30:
                    score *= 0.92
            if bin_capacity < item * 3.5:
                score *= 1.3
            elif bin_capacity > item * 11:
                score *= 0.75
            else:
                arr = np.arange(1, 5) * utilization
                score += np.sum(np.sqrt(arr)) + np.prod(np.tanh(arr / 2))
        if score < 0:
            score = abs(score) + 3 + utilization * 2
        if score > 60:
            score = 60 + np.log(score - 59) * 1.2
        if utilization > 0.85:
            score *= 1.1 + (utilization - 0.85) * 5
        priorities[i] = score
    return priorities
